ruleset:
rule "Fire detection"
    when
        Item SensorTemperature received update
    then
        // check for any temperature sensors in the house that are very high
        if (SensorTemperature.members.filter(s | s.state > 45).size > 0) {        
            if (Alarm_Fire.state != ON) {
                logInfo("sensor.rules", "Fire alarm tripped by temperature sensor!")
                Alarm_Fire.postUpdate(ON)
            }    	
        }
    end
    rule "Fire alarm"
    when
        Item Alarm_Fire received update ON
    then
        // turn on all lights
        callScript("lights_on")

        // send notifications
        notifyMyAndroid("Security", "FIRE alarm has been tripped!!!", 2)
        sendTweet("*** FIRE alarm - someone call the fire dept!!! ***")

        // send an email
        sendMail("ben@home.com", "FIRE ALARM!!", "The fire alarm has been activated!!!")
    end

rule "First floor Scene 7 - fire alarm"
when
	Item nScene_FF_Lights received command 7
then
	// FF Indoor lights
	sendCommand(sLight_FirstFl_Corridor, ON)
	sendCommand(sLight_TopFl_Corridor, ON)
	sendCommand(sLight_Study, ON)
	sendCommand(sLight_Bedroom_01, ON)
	sendCommand(sLight_Bedroom_02, ON)
	sendCommand(sLight_KidsRoom_01, ON)
end
rule "FF Actuator 1"
when
	Item sLight_FirstFl_Act01 changed
then
	// Switch ON: FF Corridor Light ON
	if (sLight_FirstFl_Act01.state == ON) {
		//logInfo("Lightscenes", "Turning on the first floor corridor light, because someone pressed the associated wall switch.")
		sendCommand(sLight_FirstFl_Corridor, ON)
	}
	// Switch OFF: FF Corridor Light OFF
	if (sLight_FirstFl_Act01.state == OFF) {
		//logInfo("Lightscenes", "Turning off the first floor corridor light, because someone pressed the associated wall switch.")
		sendCommand(sLight_FirstFl_Corridor, OFF)
	}
end

rule "First floor Scene 9 - full alarm"
when
	Item nScene_FF_Lights received command 9
then
	// FF Indoor lights
	sendCommand(sLight_FirstFl_Corridor, ON)
	sendCommand(sLight_TopFl_Corridor, ON)
	sendCommand(sLight_Study, ON)
	sendCommand(sLight_Bedroom_01, ON)
	sendCommand(sLight_Bedroom_02, ON)
	sendCommand(sLight_KidsRoom_01, ON)
end
rule "FF Actuator 1"
when
	Item sLight_FirstFl_Act01 changed
then
	// Switch ON: FF Corridor Light ON
	if (sLight_FirstFl_Act01.state == ON) {
		//logInfo("Lightscenes", "Turning on the first floor corridor light, because someone pressed the associated wall switch.")
		sendCommand(sLight_FirstFl_Corridor, ON)
	}
	// Switch OFF: FF Corridor Light OFF
	if (sLight_FirstFl_Act01.state == OFF) {
		//logInfo("Lightscenes", "Turning off the first floor corridor light, because someone pressed the associated wall switch.")
		sendCommand(sLight_FirstFl_Corridor, OFF)
	}
end

rule "Switch lights on at sunset"
when
	// Every day at sunset
	Item sSunset_Event changed to ON
then
	// Turn on outdoor lights
	logInfo("Lights", "Turning ON the front door light at sunset.")
	sendCommand(sLight_FrontDoor, ON)
	// Normal ground and first floor lights
	logInfo("Lights", "Turning ON the indoor lights at sunset.")
	sendCommand(nScene_GF_Lights, LIGHTSNORMAL)
	sendCommand(nScene_FF_Lights, LIGHTSNORMAL)
end
rule "Switch lights off at sunrise"
when
	// Every day at sunrise
	Item sSunrise_Event changed to ON
then
	// Turn off outdoor lights
	logInfo("Lights", "Turning OFF the outdoor lights at sunrise.")
	sendCommand(sLight_FrontDoor, OFF)
	sendCommand(sLight_GardenDoor, OFF)
	// Turn off indoor lights if no motion
	if(cSensor_Living_Motion.state == CLOSED) {
		logInfo("Lights", "Turning OFF the ground floor lights at sunrise, because no motion downstairs.")
		sendCommand(nScene_GF_Lights, LIGHTSOFF)
	}
	if(cSensor_FirstFl_Motion.state == CLOSED) {
		logInfo("Lights", "Turning OFF the first floor lights at sunrise, because no motion upstairs.")
		sendCommand(nScene_FF_Lights, LIGHTSOFF)
	}
end

