		postUpdate(tLastAlarmTime,new DateTimeType())
		postUpdate(strLastAlarmType,"Nachtalarm")

		// Activate sirens and strobes
		sendCommand(nSirens_GeneralMode, NIGHTALARM)

		// Turn on lights
		sendCommand(nScene_GF_Lights, NIGHTALARM)
		sendCommand(nScene_FF_Lights, NIGHTALARM)
	}
	else {
		// Deactivate if not nighttime
		postUpdate(cAlarmActivation_Night, CLOSED)
		logInfo("Alarm", "Night alarm triggered but automatically reset because it is daytime.")
	}
end
rule "Activate fire alarm"
when
	Item cAlarmActivation_Fire changed to OPEN
then
	// Set presence status
	postUpdate(nStatus_Presence, FIRE)

	// Register last alarm
	logInfo("Alarm", "Fire alarm activated.")
	postUpdate(tLastAlarmTime_Fire,new DateTimeType())
	postUpdate(tLastAlarmTime,new DateTimeType())
	postUpdate(strLastAlarmType,"Brandalarm")

	// Activate sirens and strobes
	sendCommand(nSirens_GeneralMode, FIREALARM)

	// Turn on lights
	sendCommand(nScene_GF_Lights, FIREALARM)
	sendCommand(nScene_FF_Lights, FIREALARM)
end

rule "Auto turn off night alarm"
when
	Item nStatus_Presence changed to 3
then
	if (sAlarm_Night_Auto.state == ON
	 && sAlarm_Night.state == ON
	 && cAlarmActivation_Night.state != OPEN) {
		logInfo("Alarm", "Turning off night alarm, because auto mode is on and it seems somebody is awake.")
		sendCommand(sAlarm_Night, OFF)
	}
end
rule "Activate night alarm"
when
	Item cAlarmActivation_Night changed to OPEN
then
	// It should be nighttime for this alarm to do anything
	if (sNight.state == ON) {

		// Set presence status
		postUpdate(nStatus_Presence, ALARM)

		// Register last alarm
		logInfo("Alarm", "Night alarm activated.")
		postUpdate(tLastAlarmTime_Night,new DateTimeType())
		postUpdate(tLastAlarmTime,new DateTimeType())
		postUpdate(strLastAlarmType,"Nachtalarm")

		// Activate sirens and strobes
		sendCommand(nSirens_GeneralMode, NIGHTALARM)

		// Turn on lights
		sendCommand(nScene_GF_Lights, NIGHTALARM)
		sendCommand(nScene_FF_Lights, NIGHTALARM)
	}
	else {
		// Deactivate if not nighttime
		postUpdate(cAlarmActivation_Night, CLOSED)
		logInfo("Alarm", "Night alarm triggered but automatically reset because it is daytime.")
	}
end

rule "r2 - A cada uma hora"
when
    Time cron "0 0 0/1 1/1 * ? *"
//	Time cron "0 5 0 * * ?"
then
//	logError ("CAFETEIRA", "Oie")
//	if (Alarm_MasterTimeMins.state == Unitialized || Alarm_MasterTimeMins.state == Undefined)
	if (Alarm_MasterTimeMins.state == Undefined)
	{
		postUpdate(Alarm_MasterTimeMins, 345)
//		logError ("CAFETEIRA", "Oie2")
	}

	// Desliga a cafeteira a cada uma hora se <=5 OU >=9h
	if (now.getHourOfDay <=4 || now.getHourOfDay>=10)
	{
		Tom_gTER_Cafeteira.sendCommand(OFF)
	}
end
rule "r3 - Master bedroom alarm time"
when
    Time cron "0 5 0 * * ?" or
    Item Alarm_MasterTimeMins received update 
then

	var int minutes minutes = ((Alarm_MasterTimeMins.state as DecimalType).intValue())
	logError ("CAFETEIRA", "1")

    if (masterAlarmTime != null)
	{
		// logError ("CAFETEIRA", "2")
	    masterAlarmTime.cancel()
		// logError ("CAFETEIRA", "3")
	}

    // work out when the alarm is to fire - start from midnight
	// logError ("CAFETEIRA", "4")
    var DateTime alarmTime = parse(now.getYear() + "-" + now.getMonthOfYear() + "-" + now.getDayOfMonth() + "T00:00")
	// logError ("CAFETEIRA", "5")

    // add the number of minutes selected
    alarmTime = alarmTime.plusMinutes(minutes)
	// logError ("CAFETEIRA", "6")

    // if we have already past the alarm time then set it for the following day
    if (alarmTime.beforeNow)
	{
		alarmTime = alarmTime.plusDays(1)
		// logError ("CAFETEIRA", "7")
	}

    // // create a timer to execute the alarm at the specified time
    // // masterAlarmTime = createTimer(alarmTime) 
	// // [| 
        // if (Alarm_Master.state == ON)
		// {
	// 		//logError ("CAFETEIRA", "Ligando!")
			Tom_gTER_Cafeteira.sendCommand(ON)
	// 		// createTimer(now.plusMinutes(150)) 
	// 		// [|
				Tom_gTER_Cafeteira.sendCommand(OFF)
	// 		// ]
		// }
    // ]

    // update the alarm display time    
    Alarm_MasterTime.sendCommand(String::format("%02d:%02d", alarmTime.getHourOfDay(), alarmTime.getMinuteOfHour()))
end

