rule "RGBCW -> HSB+CW"
when
    Item Lamp_ColorRGBCWString received update
then
    var rgbcw = Lamp_ColorRGBCWString.state.toString

    var r = Integer::parseInt(rgbcw.substring(0, 2), 16)
    var g = Integer::parseInt(rgbcw.substring(2, 4), 16)
    var b = Integer::parseInt(rgbcw.substring(4, 6), 16)
    //logInfo(filename, "Input Conversion: r" + r + " g" + g + " b" + b)
    var HSBType hsb = HSBType.fromRGB(r, g, b)
    //logInfo(filename, "Input Conversion: hsb" + hsb)

    var cw_dimm = Integer::parseInt(rgbcw.substring(6, 8), 16) * 100 / 255
    var ww_dimm = Integer::parseInt(rgbcw.substring(8, 10), 16) * 100 / 255
    //logInfo(filename, "Input Conversion: cw_dimm" + cw_dimm)
    //logInfo(filename, "Input Conversion: ww_dimm" + ww_dimm)

    Lamp_ColorHSB.postUpdate(hsb)
    Lamp_CWDimmer.postUpdate(cw_dimm)
    Lamp_WWDimmer.postUpdate(ww_dimm)
end
rule "HSB+CW -> RGBCW"
when
    Item Lamp_ColorHSB received command or
    Item Lamp_CWDimmer received command or
    Item Lamp_WWDimmer received command
then
    //logInfo(filename, "Command received: " + receivedCommand)
    if (receivedCommand instanceof OnOffType) {
        if (receivedCommand == ON) {
            Lamp_Power.sendCommand(ON)
        } else {
            Lamp_Power.sendCommand(OFF)
        }
    return;
    }
    var r = ((Lamp_ColorHSB.state as HSBType).getRed * 255 / 100).intValue
    var g = ((Lamp_ColorHSB.state as HSBType).getGreen * 255 / 100).intValue
    var b = ((Lamp_ColorHSB.state as HSBType).getBlue * 255 / 100).intValue
    var cw = ((Lamp_CWDimmer.state as Number) * 255 / 100).intValue
    var ww = ((Lamp_WWDimmer.state as Number) * 255 / 100).intValue
    //logInfo(filename, "Output Conversion: r" + r + " g" + g + " b" + b)
    //logInfo(filename, "Output Conversion: cw" + cw + " ww" + ww)
    var rgbcw = String.format("%02x%02x%02x%02x%02x", r, g, b, cw, ww)
    //logInfo(filename, "Output Conversion: rgbcw" + rgbcw)
    Lamp_ColorRGBCWString.sendCommand(rgbcw)
end

rule "Auto Front Doorbell"
	when
	Item Doorbell_PIRAlarm changed to ON
	then
		//KitchenHomeHubPlayURI.sendCommand("http://192.168.1.2:54321/ipcamera.jpg")	//can send jpg whilst GIF is recorded.
        if (Doorbell_RecordingMP4.state == 0 || Doorbell_RecordingMP4.state == NULL){
		var DoorbellMp4TimeStamp = new DateTimeType().format("%1$ty-%1$tm-%1$td_%1$tH-%1$tM-%1$tS").toString
		//may run out of streams if recording to 2 formats and watching unless you use gifPreroll.
        getActions("ipcamera", "ipcamera:onvif:Doorbell").recordGIF("ipcamera",5)
		getActions("ipcamera", "ipcamera:onvif:Doorbell").recordMP4(DoorbellMp4TimeStamp,5)
		}
		if (BabyMonitor.state==ON){
			KitchenHomeHubVolume.sendCommand(30)
			sendBroadcastNotification("Someone is at the door and baby is alseep.")
		}   else {
			KitchenHomeHubVolume.sendCommand(70)			
		} 
		KitchenHomeHubPlayURI.sendCommand("http://192.168.1.2:8080/static/doorbell.mp3")      
end
rule "Send doorbell GIF to HomeHub and Pushover"
when
	Item Doorbell_recordingGif changed to 0
then
	KitchenHomeHubPlayURI.sendCommand("http://192.168.1.2:54321/ipcamera.gif")
	sendPushoverMessage(pushoverBuilder("GIF from Doorbell").withApiKey("xxxxxxxxxx").withUser("xxxxxxxxxxx").withDevice("MattPhone").withAttachment("/etc/openhab2/html/Doorbell/ipcamera.gif"))
end

rule "1 Irrigation - system start"
when
	System started
then
	// initiall default settings

	if (SumRainLast24h.state == NULL) 
		SumRainLast24h.sendCommand(0)

	if (SumRainNext24h.state == NULL) 
		SumRainNext24h.sendCommand(0)

	if (MaxAllowedWindSpeed.state == NULL)
		MaxAllowedWindSpeed.sendCommand(35)

	if (MaxAllowedRain.state == NULL)
		MaxAllowedRain.sendCommand(3)

	if (IrrigationHoursBeforeSunrise.state == NULL)
		IrrigationHoursBeforeSunrise.sendCommand(1)

	if (IrrigationValveZone1Time.state == NULL)
		IrrigationValveZone1Time.sendCommand(1)

	if (IrrigationValveZone2Time.state == NULL)
		IrrigationValveZone2Time.sendCommand(1)

	if (IrrigationValveZone3Time.state == NULL)	
		IrrigationValveZone3Time.sendCommand(1)

	if (IrrigationValveZone4Time.state == NULL)	
		IrrigationValveZone4Time.sendCommand(1)

	if (IrrigationStartAtSpecificHour.state == NULL)
		IrrigationStartAtSpecificHour.sendCommand(OFF)

	if (IrrigationStartTime.state == NULL)	
		IrrigationStartTime.sendCommand(20)

	if (IrrigationHoursBeforeSunrise.state == NULL)
